const item = $input.first();
const json = item.json;

let text = "";

// 1. Tenta extrair o texto da resposta da IA
if (json.candidates && json.candidates[0] && json.candidates[0].content && json.candidates[0].content.parts) {
  text = json.candidates[0].content.parts[0].text;
} else {
  return { 
    dieta: null, 
    debug_error: "O Google respondeu, mas a estrutura não contém 'candidates'.", 
    resposta_bruta: json 
  };
}

// 2. Limpeza robusta para extrair apenas o bloco JSON
const jsonMatch = text.match(/\{[\s\S]*\}/);
let jsonString = "";

if (jsonMatch) {
  jsonString = jsonMatch[0];
} else {
  return { 
    dieta: null, 
    debug_error: "A IA gerou texto, mas não encontrei um bloco JSON válido (sem chaves {}).", 
    texto_gerado: text 
  };
}

// 3. Tenta converter o texto limpo para um objeto
try {
  const dietaObj = JSON.parse(jsonString);

  // Sucesso! Envolve o objeto na chave 'dieta' que o backend espera.
  return {
    dieta: dietaObj
  };
} catch (e) {
  return { 
    dieta: null, 
    debug_error: "Falha no JSON.parse. O texto da IA provavelmente tem um erro de sintaxe.", 
    texto_problematico: jsonString 
  };
}
